import React from "react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
} from "recharts";

export default function BusCharts({ trendData }) {
  return (
    <LineChart width={500} height={200} data={trendData}>
      <CartesianGrid strokeDasharray="3 3" />
      <XAxis dataKey="time" />
      <YAxis />
      <Tooltip />
      <Legend />
      <Line type="monotone" dataKey="Running" stroke="green" />
      <Line type="monotone" dataKey="Ghost" stroke="red" />
      <Line type="monotone" dataKey="Anomaly" stroke="orange" />
    </LineChart>
  );
}
